const res = $input.first().json;
const rows = res.values || [];
let found = null, idx = -1;
for (let i = 0; i < rows.length; i++) {
  if ((rows[i][2] || '').toString().trim() === 'Ready to Post') { found = rows[i]; idx = i; break; }
}
if (!found) throw new Error('No rows with Status = Ready to Post in Aperture Video Queue.');
const rowNumber = idx + 2;
return [{ json: {
  job_id:          (found[0] || '').trim(),
  topic:           (found[1] || '').trim(),
  drive_video_url: (found[3] || '').trim(),
  title:           (found[4] || '').trim(),
  hashtags:        (found[5] || '').trim(),
  caption:         (found[12] || '').trim(),
  thumbnail_url:   (found[13] || '').trim(),
  queue_row:       rowNumber
}}];

const { execSync } = require('child_process');
const data = $('Pick Next Ready Row').first().json;
const jobId = data.job_id;
const url   = data.drive_video_url;
if (!url) throw new Error('No drive_video_url for ' + jobId);

const contPath = '/ffmpeg/input/' + jobId + '_publish.mp4';
const cmd = 'docker exec phys_ffmpeg_runner curl -sL -o "' + contPath + '" "' + url + '" && echo DL_OK';
const res = execSync(cmd, { encoding: 'utf-8', timeout: 180000 });
if (!res.includes('DL_OK')) throw new Error('Failed to download final video from Drive for ' + jobId);

console.log('Downloaded publish source for ' + jobId + ' -> ' + contPath);
return [{ json: { ...data, publish_file_path: contPath } }];

const https = require('https');
const { execSync } = require('child_process');
const data = $('Download Video for Publishing').first().json;

function post(hostname, path, body, headers) {
  return new Promise((resolve, reject) => {
    const buf = Buffer.from(body);
    const req = https.request({ hostname, path, method: 'POST', headers: Object.assign({ 'Content-Length': buf.length }, headers) }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve({ status: res.statusCode, headers: res.headers, body: Buffer.concat(chunks).toString() }));
    });
    req.on('error', reject);
    req.write(buf);
    req.end();
  });
}

try {
  if (!$env.YOUTUBE_APERTURE_CLIENT_ID || !$env.YOUTUBE_APERTURE_CLIENT_SECRET || !$env.YOUTUBE_APERTURE_REFRESH_TOKEN)
    throw new Error('YOUTUBE_APERTURE_* env vars not set');

  const tokenBody = 'client_id=' + encodeURIComponent($env.YOUTUBE_APERTURE_CLIENT_ID) +
    '&client_secret=' + encodeURIComponent($env.YOUTUBE_APERTURE_CLIENT_SECRET) +
    '&refresh_token=' + encodeURIComponent($env.YOUTUBE_APERTURE_REFRESH_TOKEN) +
    '&grant_type=refresh_token';
  const tokenRes = await post('oauth2.googleapis.com', '/token', tokenBody, { 'Content-Type': 'application/x-www-form-urlencoded' });
  const tokenJson = JSON.parse(tokenRes.body);
  if (!tokenJson.access_token) throw new Error('YouTube token refresh failed: ' + tokenRes.body.slice(0,200));
  const accessToken = tokenJson.access_token;

  const snippet = {
    snippet: {
      title: (data.title || data.topic || 'Aperture').slice(0, 95),
      description: (data.hashtags || ''),
      tags: (data.hashtags || '').replace(/#/g, '').split(/\s+/).filter(Boolean),
      categoryId: '27'
    },
    status: { privacyStatus: 'public', selfDeclaredMadeForKids: false }
  };

  const initCmd = 'docker exec phys_ffmpeg_runner curl -sD - -o /dev/null -X POST ' +
    '-H "Authorization: Bearer ' + accessToken + '" ' +
    '-H "Content-Type: application/json; charset=UTF-8" ' +
    '-H "X-Upload-Content-Type: video/mp4" ' +
    "-d '" + JSON.stringify(snippet).replace(/'/g, "'\\''") + "' " +
    '"https://www.googleapis.com/upload/youtube/v3/videos?uploadType=resumable&part=snippet,status"';
  const initRes = execSync(initCmd, { encoding: 'utf-8', timeout: 30000 });
  const locMatch = initRes.match(/[Ll]ocation:\s*(\S+)/);
  if (!locMatch) throw new Error('YouTube resumable init failed: ' + initRes.slice(0,300));
  const uploadUrl = locMatch[1].trim();

  const putCmd = 'docker exec phys_ffmpeg_runner curl -s -X PUT ' +
    '-H "Content-Type: video/mp4" ' +
    '--upload-file "' + data.publish_file_path + '" "' + uploadUrl + '"';
  const putRes = execSync(putCmd, { encoding: 'utf-8', timeout: 600000 });
  const parsed = JSON.parse(putRes);
  if (!parsed.id) throw new Error('YouTube upload finish failed: ' + putRes.slice(0,300));

  console.log('YouTube OK -> ' + parsed.id);
  return [{ json: { platform: 'youtube', success: true, url: 'https://youtube.com/shorts/' + parsed.id } }];
} catch (e) {
  console.error('YouTube upload failed: ' + e.message);
  return [{ json: { platform: 'youtube', success: false, error: e.message } }];
}

const https = require('https');
const data = $('Download Video for Publishing').first().json;
const apiKey = $env.AYRSHARE_API_KEY;
const igId   = $env.AYRSHARE_APERTURE_IG_PROFILE_ID;
const ttId   = $env.AYRSHARE_APERTURE_TIKTOK_PROFILE_ID;
const liId   = $env.AYRSHARE_APERTURE_LINKEDIN_PROFILE_ID;

if (!apiKey) throw new Error('[PostForMe] AYRSHARE_API_KEY not set');
if (!igId)   throw new Error('[PostForMe] AYRSHARE_APERTURE_IG_PROFILE_ID not set');
if (!ttId)   throw new Error('[PostForMe] AYRSHARE_APERTURE_TIKTOK_PROFILE_ID not set');

const nl = String.fromCharCode(10);
const videoUrl = data.drive_video_url || data.video_url || '';
if (!videoUrl) throw new Error('[PostForMe] No video URL in payload. drive_video_url=' + data.drive_video_url + ' video_url=' + data.video_url);

// Clean em dashes and curly quotes from caption
const cleanCaption = (str) => str
  .replace(/—/g, '-')
  .replace(/–/g, '-')
  .replace(/‘|’/g, "'")
  .replace(/“|”/g, '"');
const caption = (cleanCaption(data.title || data.topic || '') + nl + nl + cleanCaption(data.caption || '') + nl + nl + (data.hashtags || '')).slice(0, 2190);
const accounts = [ttId];
if (liId) accounts.push(liId);

console.log('[PostForMe] Posting job ' + data.job_id + ' to TikTok+LinkedIn (' + accounts.length + ' accounts)');
console.log('[PostForMe] Video URL: ' + videoUrl);
console.log('[PostForMe] Accounts: ' + accounts.join(', '));

const media = [{ url: videoUrl }];
if (data.thumbnail_url) media[0].thumbnailUrl = data.thumbnail_url;
const body = JSON.stringify({ caption, social_accounts: accounts, media });
const buf = Buffer.from(body);

const result = await new Promise((resolve) => {
  const req = https.request({
    hostname: 'api.postforme.dev', path: '/v1/social-posts', method: 'POST',
    headers: { 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json', 'Content-Length': buf.length }
  }, (res) => {
    const chunks = [];
    res.on('data', c => chunks.push(c));
    res.on('end', () => {
      const raw = Buffer.concat(chunks).toString();
      try {
        const r = JSON.parse(raw);
        const success = res.statusCode < 300;
        const postUrls = (r.data || []).map(d => d.url || d.id || '').join(', ');
        const errMsg = success ? '' : (r.message || r.error || JSON.stringify(r).slice(0,300));
        console.log('[PostForMe] HTTP ' + res.statusCode + ' | success=' + success + (errMsg ? ' | error=' + errMsg : '') + (postUrls ? ' | urls=' + postUrls : ''));
        resolve({ success, status: res.statusCode, error: errMsg, urls: postUrls, raw: JSON.stringify(r).slice(0,400) });
      } catch(e) {
        console.log('[PostForMe] Non-JSON response HTTP ' + res.statusCode + ': ' + raw.slice(0,200));
        resolve({ success: false, status: res.statusCode, error: 'Non-JSON: ' + raw.slice(0,200), raw });
      }
    });
  });
  req.on('error', e => {
    console.log('[PostForMe] Network error: ' + e.message);
    resolve({ success: false, error: 'Network: ' + e.message });
  });
  req.write(buf); req.end();
});

return [{ json: { platform: 'postforme', success: result.success, accounts_posted: accounts.length, error: result.error || null, urls: result.urls || '', raw: result.raw } }];

const https = require('https');
const data = $('Download Video for Publishing').first().json;
function call(method, path, body) {
  return new Promise((resolve, reject) => {
    const buf = body ? Buffer.from(body) : null;
    const opts = { hostname: 'graph.facebook.com', path, method, headers: {} };
    if (buf) { opts.headers['Content-Type'] = 'application/x-www-form-urlencoded'; opts.headers['Content-Length'] = buf.length; }
    const req = https.request(opts, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => { try { resolve(JSON.parse(Buffer.concat(chunks).toString())); } catch(e) { reject(new Error('Non-JSON: ' + Buffer.concat(chunks).toString().slice(0,200))); } });
    });
    req.on('error', reject); if (buf) req.write(buf); req.end();
  });
}
try {
  const pageId = $env.FB_APERTURE_PAGE_ID;
  const token = $env.FB_APERTURE_PAGE_ACCESS_TOKEN;
  if (!pageId || !token) throw new Error('FB_APERTURE_PAGE_ID / FB_APERTURE_PAGE_ACCESS_TOKEN not set');
  const startBody = 'upload_phase=start&access_token=' + encodeURIComponent(token);
  const start = await call('POST', '/v20.0/' + pageId + '/video_reels', startBody);
  if (!start.video_id || !start.upload_url) throw new Error('FB Reels start failed: ' + JSON.stringify(start).slice(0,300));
  const _url = start.upload_url.split("://")[1] || "";
  const slashIdx = _url.indexOf("/");
  const uploadHostname = slashIdx === -1 ? _url : _url.slice(0, slashIdx);
  const uploadPath = slashIdx === -1 ? "/" : _url.slice(slashIdx);
  const upload = await new Promise((resolve, reject) => {
    const req = https.request({ hostname: uploadHostname, path: uploadPath, method: 'POST',
      headers: { 'Authorization': 'OAuth ' + token, 'file_url': data.drive_video_url }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => { try { resolve(JSON.parse(Buffer.concat(chunks).toString())); } catch(e) { resolve({ success: res.statusCode < 300 }); } });
    });
    req.on('error', reject); req.end();
  });
  const nl = String.fromCharCode(10);
  const cleanCaption = (str) => str.replace(/—/g, '-').replace(/–/g, '-').replace(/‘|’/g, "'").replace(/“|”/g, '"');
  const caption = (cleanCaption(data.title || data.topic || '') + nl + nl + cleanCaption(data.caption || '') + nl + nl + (data.hashtags || '')).slice(0, 2000);
  let finishBody = 'upload_phase=finish&video_id=' + start.video_id + '&video_state=PUBLISHED&description=' + encodeURIComponent(caption) + '&thumb_offset=5000&access_token=' + encodeURIComponent(token);
  const finish = await call('POST', '/v20.0/' + pageId + '/video_reels', finishBody);
  if (!finish.success) throw new Error('FB Reels finish failed: ' + JSON.stringify(finish).slice(0,300));
  console.log('Facebook Reels OK -> ' + start.video_id);
  return [{ json: { platform: 'facebook', success: true, url: 'https://www.facebook.com/reel/' + start.video_id } }];
} catch (e) {
  console.error('Facebook Reels upload failed: ' + e.message);
  return [{ json: { platform: 'facebook', success: false, error: e.message } }];
}

const https = require('https');
const data = $('Download Video for Publishing').first().json;

function graphGet(path, params, token) {
  return new Promise((resolve, reject) => {
    const qs = Object.entries(Object.assign({ access_token: token }, params)).map(([k,v]) => encodeURIComponent(k) + '=' + encodeURIComponent(v)).join('&');
    const req = https.request({ hostname: 'graph.facebook.com', path: path + '?' + qs, method: 'GET' }, (res) => {
      const chunks = []; res.on('data', c => chunks.push(c));
      res.on('end', () => { try { resolve(JSON.parse(Buffer.concat(chunks).toString())); } catch(e) { reject(e); } });
    }); req.on('error', reject); req.end();
  });
}
function graphPost(path, params, token) {
  return new Promise((resolve, reject) => {
    const body = Buffer.from(Object.entries(Object.assign({ access_token: token }, params)).map(([k,v]) => encodeURIComponent(k) + '=' + encodeURIComponent(v)).join('&'));
    const req = https.request({ hostname: 'graph.facebook.com', path, method: 'POST', headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'Content-Length': body.length } }, (res) => {
      const chunks = []; res.on('data', c => chunks.push(c));
      res.on('end', () => { try { resolve(JSON.parse(Buffer.concat(chunks).toString())); } catch(e) { reject(e); } });
    }); req.on('error', reject); req.write(body); req.end();
  });
}

try {
  const pageId = $env.FB_APERTURE_PAGE_ID;
  const token = $env.FB_APERTURE_PAGE_ACCESS_TOKEN;
  if (!pageId || !token) throw new Error('FB_APERTURE_PAGE_ID or FB_APERTURE_PAGE_ACCESS_TOKEN not set');

  // Step 1: Get Instagram Business Account ID from FB Page
  const pageRes = await graphGet('/v20.0/' + pageId, { fields: 'instagram_business_account' }, token);
  if (!pageRes.instagram_business_account || !pageRes.instagram_business_account.id)
    throw new Error('No Instagram account linked to FB page. Response: ' + JSON.stringify(pageRes).slice(0,200));
  const igUserId = pageRes.instagram_business_account.id;
  console.log('IG User ID: ' + igUserId);

  const nl = String.fromCharCode(10);
  const cleanCaption = (str) => str.replace(/\u2014/g, '-').replace(/\u2013/g, '-').replace(/\u2018|\u2019/g, "'").replace(/\u201C|\u201D/g, '"');
  const caption = (cleanCaption(data.title || '') + nl + nl + cleanCaption(data.caption || '') + nl + nl + (data.hashtags || '')).slice(0, 2200);

  // Step 2: Create Reels container with cover_url for custom thumbnail
  const containerParams = { media_type: 'REELS', video_url: data.drive_video_url, caption, share_to_feed: 'true' };
  if (data.thumbnail_url) containerParams.cover_url = data.thumbnail_url;
  const container = await graphPost('/v20.0/' + igUserId + '/media', containerParams, token);
  if (!container.id) throw new Error('Failed to create IG container: ' + JSON.stringify(container).slice(0,300));
  console.log('IG container created: ' + container.id);

  // Step 3: Poll until FINISHED (max 12 attempts x 15s = 3 min)
  let ready = false;
  for (let i = 0; i < 12; i++) {
    await new Promise(r => setTimeout(r, 15000));
    const status = await graphGet('/v20.0/' + container.id, { fields: 'status_code,status' }, token);
    console.log('IG status #' + (i+1) + ': ' + status.status_code);
    if (status.status_code === 'FINISHED') { ready = true; break; }
    if (status.status_code === 'ERROR') throw new Error('IG container error: ' + JSON.stringify(status));
  }
  if (!ready) throw new Error('IG container not ready after 3 minutes');

  // Step 4: Publish
  const publish = await graphPost('/v20.0/' + igUserId + '/media_publish', { creation_id: container.id }, token);
  if (!publish.id) throw new Error('IG publish failed: ' + JSON.stringify(publish).slice(0,300));
  console.log('IG published: ' + publish.id);

  return [{ json: { platform: 'instagram', success: true, url: 'https://www.instagram.com/reel/' + publish.id } }];
} catch(e) {
  console.error('Instagram Graph API failed: ' + e.message);
  return [{ json: { platform: 'instagram', success: false, error: e.message } }];
}

const data = $('Pick Next Ready Row').first().json;
const platforms = ['Upload to YouTube','Post via PostForMe','Upload to Facebook Reels','Post to Instagram'];
const results = platforms.map(n => {
  try {
    const r = $(n).first().json;
    return { node: n, platform: r.platform || n, success: r.success, error: r.error || null, url: r.url || r.urls || '' };
  } catch(e) {
    return { node: n, platform: n, success: false, error: 'Node did not run or threw: ' + e.message };
  }
});

const passed = results.filter(r => r.success).map(r => r.platform);
const failed = results.filter(r => !r.success).map(r => r.platform + ': ' + (r.error || 'unknown'));

console.log('=== Stage 3 Summary for job ' + data.job_id + ' ===');
passed.forEach(p => console.log('  PASS: ' + p));
failed.forEach(f => console.log('  FAIL: ' + f));

return [{ json: {
  job_id:      data.job_id,
  topic:       data.topic,
  title:       data.title,
  queue_row:   data.queue_row,
  all_success: passed.length > 0,
  passed,
  failed,
  results
}}];

const jobId = $('Collect Results').first().json.job_id;
const res = $input.first().json;
const rows = res.values || [];
let rowNumber = null;
for (let i = 0; i < rows.length; i++) {
  if ((rows[i][0] || '').toString().trim() === jobId) { rowNumber = i + 2; break; }
}
if (!rowNumber) { console.warn('Could not find ' + jobId + ' in Aperture Topics to mark LIVE'); }
return [{ json: { job_id: jobId, topics_row: rowNumber } }];
